function minDifference(nums) {
    const n = nums.length / 3;
    const prefix = new Array(n + 2).fill(0);
    const suffix = new Array(n + 2).fill(0);
    const window = new Set();

    for (let i = 0; i < n; ++i) window.add(nums[i]);
    prefix[0] = Array.from(window).reduce((a, b) => a + b, 0);

    for (let i = n, j = 1; i < 2 * n; ++i, ++j) {
        window.delete(nums[i - n]);
        window.add(nums[i]);
        prefix[j] = Array.from(window).reduce((a, b) => a + b, 0);
    }

    window.clear();

    for (let i = 0; i < n; ++i) window.add(nums[3 * n - i - 1]);
    suffix[n] = Array.from(window).reduce((a, b) => a + b, 0);

    for (let i = n - 1, j = 1; i < 2 * n - 1; --i, ++j) {
        window.delete(nums[3 * n - j]);
        window.add(nums[2 * n - j]);
        suffix[i] = Array.from(window).reduce((a, b) => a + b, 0);
    }

    let min_diff = Number.MAX_VALUE;

    for (let i = 0; i <= n; ++i) {
        min_diff = Math.min(min_diff, Math.abs(prefix[i] - suffix[i]));
    }

    return min_diff;
}
```

    The algorithm works as follows:
1. Initialize a prefix and suffix array of length n+2 where prefix array will store the sum of elements in the current sliding window until 2n and suffix array will store the sum of elements in the current sliding window from 3n to 2n.
2. Use a set or multiset to store elements of the sliding window which will be of size n.
3. First calculate the prefix sums by looping from n to 2n and calculate the suffix sums by looping from 3n to 2n.
4. While calculating the prefix and suffix sums, maintain a sliding window by removing the unwanted element and inserting the new element.
5. At the end, iterate through the prefix and suffix arrays and find the minimum difference between the sums of two parts in the arrays. Return the minimum difference.

