    int n = nums.length / 3;
    int[] prefix = new int[n + 2];
    int[] suffix = new int[n + 2];
    TreeSet<Integer> window = new TreeSet<>();

    for (int i = 0; i < n; ++i) window.add(nums[i]);
    prefix[0] = window.stream().mapToInt(Integer::intValue).sum();

    for (int i = n, j = 1; i < 2 * n; ++i, ++j) {
        window.remove(nums[i - n]);
        window.add(nums[i]);
        prefix[j] = window.stream().mapToInt(Integer::intValue).sum();
    }

    window.clear();

    for (int i = 0; i < n; ++i) window.add(nums[3 * n - i - 1]);
    suffix[n] = window.stream().mapToInt(Integer::intValue).sum();

    for (int i = n - 1, j = 1; i < 2 * n - 1; --i, ++j) {
        window.remove(nums[3 * n - j]);
        window.add(nums[2 * n - j]);
        suffix[i] = window.stream().mapToInt(Integer::intValue).sum();
